from flask import Flask, request
from elasticsearch_dsl import Search, Index
from elasticsearch_dsl.connections import connections

app = Flask(__name__)

# Elasticsearch connection setup
es = connections.create_connection(hosts=['localhost'])

@app.route('/execute-script', methods=['POST'])
def execute_script():
    req = request.get_json()
    
    if 'script' not in req:
        return {"error": "Missing script"}, 400
        
    s = Search(using=es, index="your-index")  # Replace with your index name
    
    script = {
      "source": req['script'],
      "lang": "painless",
    }
    
    result_set = s.extra(script=script).execute()
        
    return {"data": [hit.to_dict() for hit in result_set]}, 200

if __name__ == '__main__':
    app.run(debug=True)